from langgraph.graph import StateGraph
from langgraph.checkpoint.sqlite import SqliteSaver
from time import perf_counter

# Wrap your graph with latency profiling
def profile_llm_latency(graph, input_data, max_steps=50):
    latencies = {}
    checkpointer = SqliteSaver.from_conn_string(':memory:')
    config = {'configurable': {'thread_id': 'profile-1'}}

    start = perf_counter()
    for step in range(max_steps):
        state = graph.invoke(input_data, config, stream_mode='values')
        step_time = perf_counter() - start

        # Extract node execution times from state
        if 'timestamps' in state:
            for node, ts in state['timestamps'].items():
                if 'llm' in node.lower():
                    latencies[node] = ts

        if step_time > 2.0:
            print(f'🚨 Hot path detected: {step_time:.2f}s at step {step}')
            return latencies
    return latencies

