from litellm import acompletion
from typing import List, Dict

class BatchedLLMNode:
    def __init__(self, model='gpt-4o-mini'):
        self.model = model
        self.pending_calls: List[Dict] = []

    async def acall(self, state: Dict) -> Dict:
        # Collect all parallel requests
        self.pending_calls.append({
            'prompt': state.get('prompt'),
            'tools': state.get('tools'),
            'state_key': state.get('node_id')
        })

        # Batch execute when threshold reached
        if len(self.pending_calls) >= 3:
            batched_responses = await acompletion([
                {'model': self.model, **call} for call in self.pending_calls
            ], model=self.model)

            results = {}
            for resp, call in zip(batched_responses, self.pending_calls):
                results[call['state_key']] = resp.choices[0].message
            self.pending_calls.clear()
            return {'batched_results': results}
        return state

import numpy as np
from typing import Any

class CompressedState:
    def __init__(self):
        self.embedding_cache = {}

    def compress_embeddings(self, state: Dict[str, Any]) -> Dict[str, Any]:
        compressed = state.copy()

        for key, value in state.items():
            if isinstance(value, np.ndarray) and 'embedding' in key.lower():
                # 8-bit quantization
                quantized = (value * 127).astype(np.int8)
                compressed[key] = {
                    'data': quantized.tobytes(),
                    'shape': value.shape,
                    'dtype': str(value.dtype)
                }
                print(f'Compressed {key}: {value.nbytes/1024:.1f}KB -> {len(quantized.tobytes())/1024:.1f}KB')
        return compressed

    def decompress_embeddings(self, state: Dict[str, Any]) -> Dict[str, Any]:
        for key, value in state.items():
            if isinstance(value, dict) and 'data' in value:
                shape = value['shape']
                data = np.frombuffer(value['data'], dtype=np.int8).astype(np.float32) / 127
                data = data.reshape(shape)
                state[key] = data
        return state

# Add as graph preprocessor/postprocessor
state_compressor = CompressedState()

